const items = $input.all().map(i => i.json);
const freqThreshold = 3.0;
const targetCpa = 500;

const topSpend = [...items].sort((a,b) => b.spend - a.spend).slice(0,5);
const topEfficiency = items.filter(a => a.conversions > 0 && a.cpa).sort((a,b) => a.cpa - b.cpa).slice(0,5);
const avgCtr = items.reduce((s,i) => s + (i.ctr||0), 0) / (items.length||1);
const fatigue = items.filter(a => a.frequency > freqThreshold && (a.ctr||0) < avgCtr);
const underperformers = items.filter(a => a.spend > 0 && a.cpa && a.cpa > targetCpa);

const adsets = items.filter(i => i.entity_level === 'adset');
const totalSpend = adsets.reduce((s,i) => s + parseFloat(i.spend||0), 0);
const totalConversions = adsets.reduce((s,i) => s + parseInt(i.conversions||0), 0);
const avgCpa = totalConversions > 0 ? totalSpend / totalConversions : null;

const fatigueIds = fatigue.map(a => a.entity_id).slice(0,5).join(', ');
const ragQuery = fatigueIds ? `performance data for adsets ${fatigueIds} frequency CTR trend declining` : 'ad sets with declining CTR and rising frequency last 7 days';

return [{ json: { summary: { totalSpend, totalConversions, avgCpa, targetCpa }, top_spend: topSpend, top_efficiency: topEfficiency, fatigue_candidates: fatigue, underperformers, rag_query: ragQuery } }];

const parse = (val) => { if (typeof val === 'string') { try { return JSON.parse(val); } catch(e) { return { error: 'parse_failed', raw: val }; } } return val; };
const strategyText = $('Strategy Agent').item.json?.candidates?.[0]?.content?.parts?.[0]?.text;
const optimisationText = $('Optimisation Agent').item.json?.candidates?.[0]?.content?.parts?.[0]?.text;
return [{ json: { strategyData: parse(strategyText), optimisationData: parse(optimisationText) } }];

const parse = (val) => { if (typeof val === 'string') { try { return JSON.parse(val); } catch(e) { return { error: 'parse_failed', raw: val }; } } return val; };
const strategyData = $json.strategyData;
const optimisationData = $json.optimisationData;
const copyData = parse($('Copywriting Agent').item.json?.candidates?.[0]?.content?.parts?.[0]?.text);
const complianceData = parse($('Compliance Agent').item.json?.candidates?.[0]?.content?.parts?.[0]?.text);
const date = new Date().toISOString().split('T')[0];
const report = { date, account_id: 'YOUR_AD_ACCOUNT_ID', strategy: strategyData, optimisation: optimisationData, copy_variants: copyData, compliance: complianceData, generated_at: new Date().toISOString() };
const slackText = [`*📊 Laiqa Daily Growth Report — ${date}*`, `*Strategy:* ${strategyData?.summary||'N/A'}`, `*Top Issues:* ${(strategyData?.top_issues||[]).slice(0,3).join(', ')||'None'}`, `*Actions:* ${optimisationData?.actions?.length||0} queued`, `*Compliance:* ${complianceData?.overall_status||'N/A'}`, `*Confidence:* ${Math.round((strategyData?.confidence||0)*100)}%`].join('\n');
const token_estimate = Math.round(JSON.stringify(report).length / 4);
return [{ json: { report, slackText, actions: optimisationData?.actions||[], compliance_verdict: complianceData?.overall_status||'FAIL', token_estimate } }];
